def composition(layoutA, layoutB):
    """Return the layout equivalent to applying layoutB, then layoutA."""
    if layoutB is None:
        return layoutA

    if is_int(layoutB):
        return composition(layoutA, Layout(layoutB))

    # A tuple is a by-mode profile.  Modes not mentioned by the profile are
    # carried through unchanged; in particular, None is a no-op by the first
    # case above.
    if is_tuple(layoutB):
        assert len(layoutA) >= len(layoutB)
        return make_layout(
            chain(
                (composition(layoutA[i], layoutB[i]) for i in range(len(layoutB))),
                (layoutA[i] for i in range(len(layoutB), len(layoutA))),
            )
        )

    assert is_layout(layoutB)

    # Composition distributes over the modes of a hierarchical layout B.
    if is_tuple(layoutB.shape):
        return make_layout(composition(layoutA, layoutB[i]) for i in range(len(layoutB)))

    if layoutB.stride == 0:
        return Layout(layoutB.shape, 0)

    result_shape = []
    result_stride = []
    rest_shape = layoutB.shape
    rest_stride = layoutB.stride

    # Coalescing exposes the maximal contiguous modes of A.  A rank-1 mode of
    # B is then factored across those modes, consuming as much of its shape as
    # each mode of A can represent.
    flat_A = coalesce(layoutA)
    flat_shape = flatten(flat_A.shape)
    flat_stride = flatten(flat_A.stride)

    for curr_shape, curr_stride in zip(flat_shape[:-1], flat_stride[:-1]):
        stride_magnitude = abs(rest_stride)
        assert curr_shape % stride_magnitude == 0 or stride_magnitude % curr_shape == 0

        new_shape = min(max(1, curr_shape // stride_magnitude), rest_shape)
        if new_shape != 1:
            result_shape.append(new_shape)
            result_stride.append(rest_stride * curr_stride)

        rest_shape = rest_shape // new_shape

        # Divide the magnitude with ceiling while retaining the direction of
        # a negative stride.  (Python's // rounds negative values downward.)
        stride_sign = 1 if rest_stride > 0 else -1
        rest_stride = stride_sign * (
            (stride_magnitude + curr_shape - 1) // curr_shape
        )

    if rest_shape != 1 or len(result_shape) == 0:
        result_shape.append(rest_shape)
        result_stride.append(rest_stride * flat_stride[-1])

    if len(result_shape) == 1:
        return Layout(result_shape[0], result_stride[0])
    return Layout(tuple(result_shape), tuple(result_stride))


